def validate_id_token(id_token_str, expected_nonce):
    """
    Validate the ID token signature, claims, and nonce.
    Returns decoded claims if valid, raises an exception otherwise.
    """
    jwks_client = PyJWKClient(OIDC_CONFIG["jwks_uri"])

    try:
        signing_key = jwks_client.get_signing_key_from_jwt(id_token_str)
    except Exception as e:
        raise ValueError(f"Failed to get signing key: {e}")

    try:
        decoded = jwt.decode(
            id_token_str,
            signing_key.key,
            algorithms=["RS256", "ES256"],
            audience=OIDC_CONFIG["client_id"],
            issuer=OIDC_CONFIG["issuer"],
            options={
                "require": ["exp", "iat", "iss", "aud", "sub", "nonce"],
                "verify_exp": True,
                "verify_iat": True,
                "verify_iss": True,
                "verify_aud": True,
            }
        )
    except jwt.ExpiredSignatureError:
        raise ValueError("ID token has expired")
    except jwt.InvalidAudienceError:
        raise ValueError("ID token audience mismatch")
    except jwt.InvalidIssuerError:
        raise ValueError("ID token issuer mismatch")
    except jwt.PyJWTError as e:
        raise ValueError(f"ID token validation failed: {e}")

    # CRITICAL: Validate nonce to prevent replay attacks
    token_nonce = decoded.get("nonce")
    if not token_nonce or token_nonce != expected_nonce:
        raise ValueError(
            "Nonce mismatch - possible replay attack. "
            "Token nonce does not match session nonce."
        )

    return decoded


def login_required(f):
    """Decorator to protect routes that require authentication."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if "user" not in session:
            session["next_url"] = request.url
            return redirect(url_for("login"))
        return f(*args, **kwargs)
    return decorated_function


def admin_required(f):
    """Decorator to restrict routes to admin users (check claims/groups)."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if "user" not in session:
            session["next_url"] = request.url
            return redirect(url_for("login"))

        user = session["user"]
        # Customize this check based on your IdP's claims
        # e.g., check groups, roles, or specific email domains
        allowed_domains = os.environ.get(
            "ADMIN_ALLOWED_DOMAINS", "example.com"
        ).split(",")
        user_email = user.get("email", "")

        if not any(user_email.endswith(f"@{d.strip()}") for d in allowed_domains):
            abort(403, description="Access restricted to admin users.")

        return f(*args, **kwargs)
    return decorated_function


