@app.route("/callback/process", methods=["POST"])
def callback_process():
    """Process the ID token from the implicit flow callback."""
    id_token_str = request.form.get("id_token")
    state = request.form.get("state")

    if not id_token_str:
        abort(400, description="Missing ID token")

    # Validate state parameter (CSRF protection)
    expected_state = session.pop("oidc_state", None)
    if not expected_state or state != expected_state:
        app.logger.warning("State mismatch in OIDC callback - possible CSRF attack")
        abort(403, description="Invalid state parameter. Possible CSRF attack.")

    # Retrieve nonce from session for validation
    expected_nonce = session.pop("oidc_nonce", None)
    if not expected_nonce:
        app.logger.warning("No nonce found in session during callback")
        abort(400, description="Session expired or invalid. Please try logging in again.")

    # Validate and decode the ID token
